import jwt
import datetime
import os

def generate_jwt_token(user_id: str, role: str) -> str:
    """
    Generates a JWT token for user authentication.

    Args:
        user_id (str): The unique identifier for the user.
        role (str): The role of the user (e.g., 'admin', 'user').

    Returns:
        str: The encoded JWT token.
    """
    # It's crucial to use a strong, secret key for signing the JWT.
    # In a real application, load this from environment variables or a secure key management system.
    # For demonstration, we'll use a simple placeholder.
    # DO NOT use 'your-secret-key' in production.
    secret_key = os.environ.get("JWT_SECRET_KEY", "your-super-secret-key-that-no-one-will-guess")

    # Define the payload for the JWT
    payload = {
        "user_id": user_id,
        "role": role,
        "exp": datetime.datetime.utcnow() + datetime.timedelta(hours=1),  # Token expiration time (e.g., 1 hour)
        "iat": datetime.datetime.utcnow(),  # Issued at time
    }

    # Encode the JWT
    encoded_jwt = jwt.encode(payload, secret_key, algorithm="HS256")

    return encoded_jwt